+        min_observations: 20,
+        window_size: 100,
+    };
+    let mut state = ConformalState::new(config);
+    // Add 10 out-of-bounds observations — still valid because < min_observations
+    for _ in 0..10 {
+        state.observe(false);
+    }
+    assert!(state.is_valid());
+}
